"use client"

import * as React from "react"
import { Check } from "lucide-react"

import { cn } from "@/lib/utils"

type StepperProps = {
  activeStep?: number
  defaultActiveStep?: number
  onStepChange?: (step: number) => void
  orientation?: "horizontal" | "vertical"
}

type StepperContextProps = {
  activeStep: number
  onStepChange: (step: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)

  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }

  return context
}

type StepperItemContextProps = {
  step: number
  state: "active" | "completed" | "inactive"
}

const StepperItemContext =
  React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)

  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }

  return context
}

function Stepper({
  activeStep: activeStepProp,
  defaultActiveStep = 1,
  onStepChange: onStepChangeProp,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & StepperProps) {
  const [activeStepState, setActiveStepState] =
    React.useState(defaultActiveStep)

  const activeStep = activeStepProp ?? activeStepState

  const onStepChange = React.useCallback(
    (step: number) => {
      if (activeStepProp === undefined) {
        setActiveStepState(step)
      }
      onStepChangeProp?.(step)
    },
    [activeStepProp, onStepChangeProp]
  )

  return (
    <StepperContext.Provider
      value={{
        activeStep,
        onStepChange,
        orientation,
      }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex gap-4",
          orientation === "horizontal" ? "flex-col" : "flex-row",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  const state =
    step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-step={step}
        className={cn(
          "group/stepper-item relative flex items-center gap-2",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onStepChange } = useStepper()
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      className={cn(
        "flex items-center gap-3 rounded-lg text-left outline-none transition-colors focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:outline-1 focus-visible:outline-ring disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => onStepChange(step)}
      {...props}
    >
      {children}
    </button>
  )
}

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { state, step } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={state}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
        state === "completed" &&
          "border-primary bg-primary text-primary-foreground",
        state === "active" && "border-primary bg-primary text-primary-foreground",
        state === "inactive" && "border-muted bg-muted text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? (state === "completed" ? (
        <Check className="size-4" />
      ) : (
        step
      ))}
    </span>
  )
}

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { state } = useStepperItem()

  return (
    <span
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-medium transition-colors",
        state === "active" && "text-foreground",
        state === "completed" && "text-foreground",
        state === "inactive" && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  const { state } = useStepperItem()

  return (
    <span
      data-slot="stepper-description"
      data-state={state}
      className={cn(
        "text-xs text-muted-foreground transition-colors",
        state === "active" && "text-muted-foreground",
        state === "inactive" && "text-muted-foreground/60",
        className
      )}
      {...props}
    />
  )
}

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "shrink-0 bg-border transition-colors",
        orientation === "horizontal" ? "h-px flex-1" : "ml-4 w-px min-h-4",
        className
      )}
      {...props}
    />
  )
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (step !== activeStep) {
    return null
  }

  return (
    <div
      data-slot="stepper-content"
      data-step={step}
      className={cn("mt-2", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

